echo ============================================================
echo  App:       dist\WildKeys\WildKeys.exe
echo  Installer: dist\WildKeys-Setup.exe
echo ============================================================
echo  Double-click WildKeys-Setup.exe to install shortcuts + app.
echo  User data is stored in %%LOCALAPPDATA%%\WildKeys
echo ============================================================
endlocal

"""Global hotkeys and random line paste (runs in worker process only)."""

from __future__ import annotations

import random
import sys
import threading
import time
from typing import Callable

import pyperclip
from pynput.keyboard import Controller, GlobalHotKeys, Key

from storage import HOTKEY_STATUS, KEYS, Store, format_paste_line, write_status

StatusCallback = Callable[[str], None]


def _win_send_ctrl_v() -> bool:
    """Send Ctrl+V via Win32 keybd_event (more reliable than pynput into many apps)."""
    try:
        import ctypes

        user32 = ctypes.windll.user32  # type: ignore[attr-defined]
        KEYEVENTF_KEYUP = 0x0002
        VK_CONTROL = 0x11
        VK_V = 0x56
        # Ensure modifiers from the hotkey chord are released first
        for vk in (0x11, 0x12, 0x10):  # Ctrl, Alt, Shift
            user32.keybd_event(vk, 0, KEYEVENTF_KEYUP, 0)
        time.sleep(0.02)
        user32.keybd_event(VK_CONTROL, 0, 0, 0)
        user32.keybd_event(VK_V, 0, 0, 0)
        user32.keybd_event(VK_V, 0, KEYEVENTF_KEYUP, 0)
        user32.keybd_event(VK_CONTROL, 0, KEYEVENTF_KEYUP, 0)
        return True
    except Exception:
        return False


def _is_wildkeys_foreground() -> bool:
    """True when the WildKeys window is focused (in-app testing)."""
    if sys.platform != "win32":
        return False
    try:
        import ctypes

        user32 = ctypes.windll.user32  # type: ignore[attr-defined]
        hwnd = user32.GetForegroundWindow()
        if not hwnd:
            return False
        length = int(user32.GetWindowTextLengthW(hwnd))
        buf = ctypes.create_unicode_buffer(length + 1)
        user32.GetWindowTextW(hwnd, buf, length + 1)
        title = (buf.value or "").strip().lower()
        return "wildkeys" in title
    except Exception:
        return False


class HotkeyEngine:
    """Listens for Ctrl+Alt+Q W R T Y U I D G K and pastes a random line."""

    def __init__(
        self,
        store: Store,
        on_status: StatusCallback | None = None,
    ) -> None:
        self.store = store
        self.on_status = on_status
        self._controller = Controller()
        self._listener: GlobalHotKeys | None = None
        self._lock = threading.Lock()
        self._busy = False
        self._running = False

    def start(self) -> None:
        with self._lock:
            if self._running:
                return
            mapping = {f"<ctrl>+<alt>+{k}": self._make_handler(k) for k in KEYS}
            self._listener = GlobalHotKeys(mapping)
            self._listener.daemon = True
            self._listener.start()
            self._running = True
            self._notify(HOTKEY_STATUS)

    def stop(self) -> None:
        with self._lock:
            listener = self._listener
            self._listener = None
            self._running = False
        if listener is not None:
            try:
                listener.stop()
            except Exception:
                pass
        self._notify("Hotkeys paused")

    def is_running(self) -> bool:
        return self._running

    def _make_handler(self, key: str) -> Callable[[], None]:
        def handler() -> None:
            threading.Thread(target=self._fire, args=(key,), daemon=True).start()

        return handler

    def _fire(self, key: str) -> None:
        self.store.reload_if_changed()

        if not self.store.is_enabled():
            self._notify(f"Ctrl+Alt+{key.upper()} ignored · app paused")
            return

        if not self.store.is_key_enabled(key):
            self._notify(f"Ctrl+Alt+{key.upper()} ignored · shortcut off")
            return

        with self._lock:
            if self._busy:
                return
            self._busy = True

        try:
            lines = [ln for ln in self.store.get_lines(key) if ln.strip()]
            if not lines:
                self._notify(f"Ctrl+Alt+{key.upper()} · empty list")
                return

            text = format_paste_line(random.choice(lines))
            preview = text if len(text) <= 48 else text[:45] + "…"
            # Exactly one paste path:
            # - WildKeys focused → UI inject only (WebView ignores synthetic Ctrl+V)
            # - Other app focused → OS Ctrl+V only (no UI inject payload)
            if _is_wildkeys_foreground():
                self._notify(
                    f"Ctrl+Alt+{key.upper()} → {preview}",
                    extra={
                        "paste": text,
                        "paste_ts": time.time(),
                        "paste_key": key,
                    },
                )
            else:
                time.sleep(0.25)
                ok = self._paste_text(text)
                if ok:
                    self._notify(f"Ctrl+Alt+{key.upper()} → {preview}")
                else:
                    self._notify(f"Ctrl+Alt+{key.upper()} · paste failed")
        finally:
            with self._lock:
                self._busy = False

    def _paste_text(self, text: str) -> bool:
        """Clipboard + Ctrl+V. Always leave text on clipboard briefly for WebView fallback."""
        try:
            try:
                previous = pyperclip.paste()
            except Exception:
                previous = None

            pyperclip.copy(text)
            time.sleep(0.06)

            if sys.platform == "win32":
                ok = _win_send_ctrl_v()
            else:
                ok = False

            if not ok:
                # Fallback: pynput
                try:
                    kb = self._controller
                    for k in (Key.ctrl, Key.alt, Key.shift):
                        try:
                            kb.release(k)
                        except Exception:
                            pass
                    time.sleep(0.02)
                    kb.press(Key.ctrl)
                    kb.press("v")
                    kb.release("v")
                    kb.release(Key.ctrl)
                    ok = True
                except Exception:
                    ok = False

            if previous is not None:

                def restore() -> None:
                    # Longer delay so in-app / slow targets can still paste
                    time.sleep(0.9)
                    try:
                        pyperclip.copy(previous)
                    except Exception:
                        pass

                threading.Thread(target=restore, daemon=True).start()
            return ok
        except Exception:
            return False

    def _notify(self, message: str, extra: dict | None = None) -> None:
        write_status(message, extra=extra)
        if self.on_status:
            try:
                self.on_status(message)
            except Exception:
                pass

"""
WildKeys — UI process (no keyboard hooks here).
Hotkeys run in a separate worker.py process.
Close (X) hides to tray; minimize uses the taskbar as usual.
"""

from __future__ import annotations

import atexit
import random
import subprocess
import sys
import threading
import time
from pathlib import Path

import webview

from paths import data_dir, install_dir, is_frozen, resource_dir
from storage import (
    HOTKEY_STATUS,
    KEYS,
    Store,
    format_paste_line,
    read_status,
    write_status,
)

APP_DIR = install_dir()
UI_PATH = resource_dir() / "ui" / "index.html"
# Window taskbar, tray, and (when frozen) process icon source
ICON_PATH = resource_dir() / "ui" / "logo.ico"
WORKER_PATH = APP_DIR / "worker.py"
STOP_PATH = data_dir() / "worker.stop"


class Api:
    """
    JS bridge.

    IMPORTANT: only public *methods* may live without a leading underscore.
    pywebview walks public attributes and will try to expose nested objects
    like Store / Window / Tray — that breaks API injection ("bridge not ready").
    """

    def __init__(self) -> None:
        self._store = Store()
        self._worker: subprocess.Popen | None = None
        self._last_ui_status = "Ready"
        self._window: webview.Window | None = None
        self._tray: object | None = None
        self._maximized = False

    # ── window chrome (frameless custom title bar) ─────────
    def window_minimize(self) -> dict:
        if self._window is not None:
            try:
                self._window.minimize()
            except Exception:
                pass
        return {"ok": True}

    def window_toggle_maximize(self) -> dict:
        if self._window is None:
            return {"maximized": self._maximized}
        try:
            if self._maximized:
                self._window.restore()
                self._maximized = False
            else:
                self._window.maximize()
                self._maximized = True
        except Exception:
            pass
        return {"maximized": self._maximized}

    def window_close(self) -> dict:
        """Close (X) → tray, same as native close behavior."""
        tray = self._tray
        if tray is not None:
            try:
                tray.hide_to_tray()  # type: ignore[attr-defined]
            except Exception:
                pass
        elif self._window is not None:
            try:
                self._window.hide()
            except Exception:
                pass
        return {"ok": True}

    def window_is_maximized(self) -> dict:
        return {"maximized": self._maximized}

    def window_drag_start(self) -> dict:
        """Snapshot window position for custom title-bar dragging."""
        if self._window is None:
            return {"x": 0, "y": 0, "maximized": self._maximized}
        try:
            if self._maximized:
                try:
                    self._window.restore()
                except Exception:
                    pass
                self._maximized = False
            return {
                "x": int(self._window.x or 0),
                "y": int(self._window.y or 0),
                "maximized": self._maximized,
            }
        except Exception:
            return {"x": 0, "y": 0, "maximized": self._maximized}

    def window_drag_move(self, x: int, y: int) -> dict:
        if self._window is None:
            return {"ok": False}
        try:
            self._window.move(int(x), int(y))
            return {"ok": True}
        except Exception:
            return {"ok": False}

    def boot(self) -> dict:
        """Called once from JS when bridge is ready — keep this fast."""
        if self._store.is_enabled():
            self._last_ui_status = HOTKEY_STATUS
            self._ensure_worker_async()
        else:
            self._last_ui_status = "Hotkeys paused"
            write_status(self._last_ui_status)
        return self.get_state()

    def ping(self) -> dict:
        """Tiny health check used by the UI to confirm the bridge is live."""
        return {"ok": True, "ts": time.time()}

    def shutdown(self) -> None:
        self._stop_worker()

    def get_state(self) -> dict:
        """Deck metadata only (no full line payloads) for a fast bridge."""
        self._store.reload_if_changed()
        snap = self._store.snapshot()
        status = read_status()
        message = status.get("message") or self._last_ui_status

        cards = []
        for k in KEYS:
            item = snap["keys"][k]
            lines = item.get("lines") or []
            cards.append(
                {
                    "key": k,
                    "shortcut": f"Ctrl+Alt+{k.upper()}",
                    "label": item.get("label") or k.upper(),
                    "count": len(lines),
                    "enabled": bool(item.get("enabled", True)),
                }
            )
        return {
            "enabled": snap["enabled"],
            "status": message,
            "statusTs": status.get("ts") or 0,
            "revision": self._store.revision(),
            "hotkeysRunning": self._worker_alive(),
            "cards": cards,
        }

    def get_key(self, key: str) -> dict:
        """Full list body for one shortcut (lazy-loaded by the editor)."""
        key = str(key or "").lower()
        if key not in KEYS:
            return {
                "ok": False,
                "key": key,
                "label": "",
                "lines": [],
                "count": 0,
                "enabled": False,
            }
        self._store.reload_if_changed()
        snap = self._store.snapshot()
        item = snap["keys"][key]
        lines = list(item.get("lines") or [])
        return {
            "ok": True,
            "key": key,
            "shortcut": f"Ctrl+Alt+{key.upper()}",
            "label": item.get("label") or key.upper(),
            "lines": lines,
            "count": len(lines),
            "enabled": bool(item.get("enabled", True)),
        }

    def poll(self) -> dict:
        status = read_status()
        try:
            rev = self._store.path.stat().st_mtime
        except OSError:
            rev = 0
        enabled = True
        try:
            enabled = self._store.is_enabled()
        except Exception:
            pass
        return {
            "status": status.get("message") or self._last_ui_status,
            "statusTs": status.get("ts") or 0,
            "revision": rev,
            "enabled": enabled,
            "hotkeysRunning": self._worker_alive(),
            "paste": status.get("paste") or "",
            "pasteTs": status.get("paste_ts") or 0,
            "pasteKey": status.get("paste_key") or "",
        }

    def set_enabled(self, enabled: bool) -> dict:
        self._store.set_enabled(bool(enabled))
        if enabled:
            self._last_ui_status = HOTKEY_STATUS
            self._ensure_worker_async()
        else:
            self._last_ui_status = "Hotkeys paused"
        write_status(self._last_ui_status)
        return self.get_state()

    def save_key(self, key: str, label: str, text: str) -> dict:
        key = str(key or "").lower()
        if not str(label or "").strip():
            state = self.get_state()
            state["ok"] = False
            state["message"] = "Please enter a list name before saving."
            return state
        lines = text.replace("\r\n", "\n").replace("\r", "\n").split("\n")
        try:
            self._store.update_key(key, label=label, lines=lines)
        except ValueError as exc:
            state = self.get_state()
            state["ok"] = False
            state["message"] = str(exc)
            return state
        self._last_ui_status = f"Saved · Ctrl+Alt+{str(key).upper()}"
        write_status(self._last_ui_status)
        state = self.get_state()
        detail = self.get_key(key)
        state["activeKey"] = detail
        state["ok"] = True
        return state

    def set_key_enabled(self, key: str, enabled: bool) -> dict:
        try:
            self._store.set_key_enabled(key, bool(enabled))
        except ValueError as exc:
            self._last_ui_status = str(exc)
            write_status(self._last_ui_status)
            state = self.get_state()
            state["ok"] = False
            state["message"] = str(exc)
            return state
        state_word = "on" if enabled else "off"
        self._last_ui_status = f"Ctrl+Alt+{str(key).upper()} · {state_word}"
        write_status(self._last_ui_status)
        state = self.get_state()
        state["ok"] = True
        return state

    def pick_preview(self, key: str) -> dict:
        self._store.reload_if_changed()
        lines = self._store.get_lines(key)
        if not lines:
            return {"ok": False, "text": "", "message": "List is empty"}
        text = random.choice(lines)
        return {"ok": True, "text": text, "message": "Preview pick"}

    def fire_hotkey(self, key: str) -> dict:
        key = str(key or "").lower()
        self._store.reload_if_changed()
        if key not in KEYS:
            return {"ok": False, "text": "", "message": "Unknown key"}
        if not self._store.is_enabled():
            return {"ok": False, "text": "", "message": "App paused (Armed off)"}
        if not self._store.is_key_enabled(key):
            return {"ok": False, "text": "", "message": "Shortcut disabled"}
        lines = [ln for ln in self._store.get_lines(key) if ln.strip()]
        if not lines:
            return {"ok": False, "text": "", "message": "Empty list"}
        text = format_paste_line(random.choice(lines))
        return {"ok": True, "text": text, "message": f"Ctrl+Alt+{key.upper()}"}

    def _worker_alive(self) -> bool:
        return self._worker is not None and self._worker.poll() is None

    def _ensure_worker_async(self) -> None:
        if self._worker_alive():
            return
        threading.Thread(target=self._ensure_worker, daemon=True).start()

    def _ensure_worker(self) -> None:
        if self._worker_alive():
            return
        try:
            if STOP_PATH.exists():
                STOP_PATH.unlink()
        except OSError:
            pass

        creationflags = 0
        if sys.platform == "win32":
            creationflags = getattr(subprocess, "CREATE_NO_WINDOW", 0)

        try:
            if is_frozen():
                # Same packaged exe, worker entry via --worker
                cmd = [sys.executable, "--worker"]
            else:
                cmd = [sys.executable, str(WORKER_PATH)]
            self._worker = subprocess.Popen(
                cmd,
                cwd=str(APP_DIR),
                creationflags=creationflags,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
            )
            write_status(HOTKEY_STATUS)
        except Exception as exc:
            self._worker = None
            write_status(f"Could not start worker: {exc}")

    def _stop_worker(self) -> None:
        try:
            STOP_PATH.parent.mkdir(parents=True, exist_ok=True)
            STOP_PATH.write_text("1", encoding="utf-8")
        except OSError:
            pass

        proc = self._worker
        self._worker = None
        if proc is None:
            return
        try:
            proc.wait(timeout=0.8)
        except Exception:
            try:
                proc.terminate()
            except Exception:
                pass
            try:
                proc.wait(timeout=0.5)
            except Exception:
                try:
                    proc.kill()
                except Exception:
                    pass
        try:
            if STOP_PATH.exists():
                STOP_PATH.unlink()
        except OSError:
            pass


class TrayController:
    """System tray: close-to-tray, restore, real quit."""

    def __init__(self, window: webview.Window, api: Api) -> None:
        self.window = window
        self.api = api
        self._icon = None
        self._thread: threading.Thread | None = None
        self._allow_close = False
        self._started = False

    def start(self) -> None:
        if self._started:
            return
        try:
            import pystray
            from PIL import Image
        except ImportError:
            return

        try:
            if ICON_PATH.exists():
                image = Image.open(ICON_PATH).convert("RGBA")
                image = image.resize((64, 64), Image.Resampling.LANCZOS)
            else:
                image = Image.new("RGBA", (64, 64), (196, 120, 90, 255))
        except Exception:
            image = Image.new("RGBA", (64, 64), (196, 120, 90, 255))

        menu = pystray.Menu(
            pystray.MenuItem("Open WildKeys", self._on_show, default=True),
            pystray.MenuItem("Quit", self._on_quit),
        )
        self._icon = pystray.Icon("WildKeys", image, "WildKeys", menu)

        def run_icon() -> None:
            assert self._icon is not None
            self._icon.run()

        self._thread = threading.Thread(target=run_icon, daemon=True)
        self._thread.start()
        self._started = True

    def stop(self) -> None:
        if self._icon is not None:
            try:
                self._icon.stop()
            except Exception:
                pass
            self._icon = None
        self._started = False

    def hide_to_tray(self) -> None:
        try:
            self.window.hide()
        except Exception:
            pass
        if not self._started:
            self.start()

    def show_window(self) -> None:
        try:
            self.window.show()
        except Exception:
            pass
        try:
            self.window.restore()
        except Exception:
            pass
        try:
            self.window.on_top = True
            self.window.on_top = False
        except Exception:
            pass

    def _on_show(self, _icon=None, _item=None) -> None:
        try:
            self.show_window()
        except Exception:
            pass

    def _on_quit(self, _icon=None, _item=None) -> None:
        self._allow_close = True
        self.stop()
        self.api.shutdown()
        try:
            self.window.destroy()
        except Exception:
            try:
                self.window.destroy()
            except Exception:
                pass
            import os

            os._exit(0)

    def handle_closing(self) -> bool:
        if self._allow_close:
            self.stop()
            self.api.shutdown()
            return True
        if not self._started:
            self.start()
        if not self._started:
            self.api.shutdown()
            return True
        self.hide_to_tray()
        return False


def main() -> int:
    if not UI_PATH.exists():
        print(f"UI missing: {UI_PATH}", file=sys.stderr)
        return 1

    try:
        if STOP_PATH.exists():
            STOP_PATH.unlink()
    except OSError:
        pass

    api = Api()
    atexit.register(api.shutdown)

    window = webview.create_window(
        title="WildKeys",
        url=UI_PATH.as_uri(),
        js_api=api,
        width=1200,
        height=720,
        min_size=(860, 600),
        background_color="#E6DED2",
        text_select=True,
        frameless=True,
        easy_drag=False,
    )

    tray = TrayController(window, api)
    # Private attrs only — pywebview must not walk these when building JS API
    api._window = window
    api._tray = tray

    def on_closing() -> bool:
        return tray.handle_closing()

    window.events.closing += on_closing

    def on_loaded() -> None:
        def _tray_later() -> None:
            time.sleep(0.4)
            try:
                tray.start()
            except Exception:
                pass

        threading.Thread(target=_tray_later, daemon=True).start()
        if api._store.is_enabled():
            api._ensure_worker_async()

    window.events.loaded += on_loaded

    start_kwargs: dict = {"debug": False}
    if ICON_PATH.exists():
        start_kwargs["icon"] = str(ICON_PATH)

    try:
        webview.start(gui="edgechromium", **start_kwargs)
    except Exception:
        webview.start(**start_kwargs)

    tray.stop()
    api.shutdown()
    return 0


if __name__ == "__main__":
    # Packaged builds re-launch this exe with --worker for the hotkey process.
    if "--worker" in sys.argv:
        from single_instance import claim as _claim
        from worker import main as worker_main

        if not _claim("worker"):
            raise SystemExit(0)
        raise SystemExit(worker_main())

    from single_instance import claim as _claim

    if not _claim("ui"):
        raise SystemExit(0)
    raise SystemExit(main())

"""App paths for dev vs frozen (PyInstaller) installs."""

from __future__ import annotations

import os
import sys
from pathlib import Path


def is_frozen() -> bool:
    return bool(getattr(sys, "frozen", False))


def resource_dir() -> Path:
    """Bundled read-only assets (ui/, etc.)."""
    if is_frozen():
        # PyInstaller onedir/onefile extract / _internal
        meipass = getattr(sys, "_MEIPASS", None)
        if meipass:
            return Path(meipass)
        return Path(sys.executable).resolve().parent
    return Path(__file__).resolve().parent


def install_dir() -> Path:
    """Directory containing the main executable (or project root in dev)."""
    if is_frozen():
        return Path(sys.executable).resolve().parent
    return Path(__file__).resolve().parent


def data_dir() -> Path:
    """
    Writable runtime data (lists, status, locks).

    Frozen installs use %LOCALAPPDATA%\\WildKeys so Program Files stays read-only.
    Dev uses <project>/data.
    """
    if is_frozen():
        base = Path(os.environ.get("LOCALAPPDATA") or Path.home() / "AppData" / "Local")
        path = base / "WildKeys"
    else:
        path = install_dir() / "data"
    path.mkdir(parents=True, exist_ok=True)
    return path

/* WildKeys UI — polls Python; never relies on evaluate_js pushes */

const $ = (sel) => document.querySelector(sel);

const state = {
  enabled: true,
  cards: [],
  selected: null,
  dirty: false,
  revision: 0,
  statusTs: 0,
  pasteTs: 0,
  booted: false,
  saving: false,
};

const els = {
  deck: $("#deck"),
  enabledToggle: $("#enabledToggle"),
  toggleLabel: $("#toggleLabel"),
  editorTitle: $("#editorTitle"),
  editorShortcut: $("#editorShortcut"),
  editorKeyLetter: $("#editorKeyLetter"),
  labelInput: $("#labelInput"),
  saveSuccessGif: $("#saveSuccessGif"),
  linesEditor: $("#linesEditor"),
  lineGutter: $("#lineGutter"),
  linesInput: $("#linesInput"),
  lineCount: $("#lineCount"),
  saveBtn: $("#saveBtn"),
  previewBtn: $("#previewBtn"),
  toast: $("#toast"),
  previewModal: $("#previewModal"),
  previewModalText: $("#previewModalText"),
  previewModalClose: $("#previewModalClose"),
  previewModalDone: $("#previewModalDone"),
  unsavedModal: $("#unsavedModal"),
  unsavedModalClose: $("#unsavedModalClose"),
  unsavedKeepBtn: $("#unsavedKeepBtn"),
  unsavedDiscardBtn: $("#unsavedDiscardBtn"),
  errorModal: $("#errorModal"),
  errorModalClose: $("#errorModalClose"),
  errorModalOk: $("#errorModalOk"),
  errorModalLead: $("#errorModalLead"),
  errorModalTitle: $("#errorModalTitle"),
  titlebar: $("#titlebar"),
  winMin: $("#winMin"),
  winClose: $("#winClose"),
  titlebarDrag: $("#titlebarDrag"),
  loadingModal: $("#loadingModal"),
};

function api() {
  return window.pywebview?.api ?? null;
}

function apiReady() {
  const a = api();
  if (!a || typeof a !== "object") return false;
  // Prefer explicit methods; fall back to any bound API surface
  if (typeof a.boot === "function") return true;
  if (typeof a.ping === "function") return true;
  if (typeof a.get_state === "function") return true;
  try {
    return Object.keys(a).length > 0;
  } catch (_) {
    return false;
  }
}

async function call(method, ...args) {
  // Brief retry — methods can appear a tick after pywebviewready
  for (let i = 0; i < 40; i += 1) {
    const a = api();
    if (a && typeof a[method] === "function") {
      return a[method](...args);
    }
    await sleep(50);
  }
  throw new Error("Bridge not ready");
}

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

/** Wait until pywebview has exposed the Python API (event + poll fallback). */
function waitForBridge(timeoutMs = 60000) {
  return new Promise((resolve, reject) => {
    if (apiReady()) {
      resolve();
      return;
    }

    let settled = false;
    const finish = (fn, arg) => {
      if (settled) return;
      settled = true;
      window.removeEventListener("pywebviewready", onReady);
      clearInterval(poll);
      clearTimeout(timer);
      fn(arg);
    };

    const onReady = () => {
      // finish.js dispatches ready right after _createApi — poll a few frames
      let n = 0;
      const poke = () => {
        if (apiReady()) {
          finish(resolve);
          return;
        }
        n += 1;
        if (n < 40) setTimeout(poke, 25);
      };
      poke();
    };

    window.addEventListener("pywebviewready", onReady);

    const poll = setInterval(() => {
      if (apiReady()) finish(resolve);
    }, 40);

    const timer = setTimeout(() => {
      finish(reject, new Error("bridge-timeout"));
    }, timeoutMs);
  });
}

function lineCountFromText(text) {
  return text
    .split(/\r?\n/)
    .map((l) => l.trim())
    .filter(Boolean).length;
}

function showToast(message, kind = "") {
  els.toast.hidden = false;
  els.toast.className = "toast" + (kind ? ` ${kind}` : "");
  els.toast.textContent = message;
  clearTimeout(showToast._t);
  showToast._t = setTimeout(() => {
    els.toast.hidden = true;
  }, 3200);
}

function setStatus(_text, _mode = "on") {
  // Status pill removed from UI; keep for internal no-op calls
}

function applyState(payload, { forceEditor = false } = {}) {
  if (!payload) return;

  state.enabled = !!payload.enabled;
  // Preserve any already-loaded lines when refreshing metadata-only cards
  const prevLines = {};
  for (const c of state.cards || []) {
    if (c.lines) prevLines[c.key] = c.lines;
  }
  state.cards = (payload.cards || []).map((c) => ({
    ...c,
    lines: c.lines != null ? c.lines : prevLines[c.key],
  }));
  if (payload.revision != null) state.revision = payload.revision;
  if (payload.statusTs != null) state.statusTs = payload.statusTs;

  // Optional full body for the active key (e.g. after save)
  if (payload.activeKey && payload.activeKey.key) {
    const ak = payload.activeKey;
    const idx = state.cards.findIndex((c) => c.key === ak.key);
    if (idx >= 0) {
      state.cards[idx] = { ...state.cards[idx], ...ak, lines: ak.lines || [] };
    }
  }

  if (els.enabledToggle) {
    els.enabledToggle.checked = state.enabled;
  }
  if (els.toggleLabel) {
    els.toggleLabel.textContent = state.enabled ? "Armed" : "Paused";
  }

  const mode = state.enabled ? "on" : "off";
  setStatus(
    payload.status || (state.enabled ? "Hotkeys armed" : "Hotkeys paused"),
    mode
  );

  renderDeck();

  if (state.selected) {
    const card = state.cards.find((c) => c.key === state.selected);
    if (card && (!state.dirty || forceEditor)) {
      if (card.lines != null) {
        fillEditor(card);
        state.dirty = false;
      }
    }
  }
}

function renderDeck() {
  const prevFocusKey = document.activeElement?.dataset?.key;
  const armed = state.enabled;
  els.deck.innerHTML = "";
  for (const card of state.cards) {
    const keyOn = armed && card.enabled !== false;
    const row = document.createElement("div");
    row.className =
      "deck-row" + (keyOn ? "" : " key-off") + (armed ? "" : " global-paused");
    row.dataset.key = card.key;
    row.setAttribute("role", "listitem");

    const toggleTitle = !armed
      ? "Turn Armed on to enable shortcuts"
      : keyOn
        ? "Shortcut on"
        : "Shortcut off";

    row.innerHTML = `
      <div class="key-combo" aria-label="${escapeHtml(card.shortcut)}">
        <span class="key-badge mod">Ctrl</span>
        <span class="key-badge mod">Alt</span>
        <span class="key-badge letter">${card.key.toUpperCase()}</span>
      </div>
      <button type="button" class="card${
        state.selected === card.key ? " active" : ""
      }" data-key="${card.key}">
        <div class="card-label">${escapeHtml(card.label)}</div>
      </button>
      <label class="toggle toggle-sm row-toggle${
        armed ? "" : " is-locked"
      }" title="${escapeHtml(toggleTitle)}">
        <input type="checkbox" class="key-enabled" data-key="${card.key}" ${
      keyOn ? "checked" : ""
    } ${armed ? "" : "disabled"} />
        <span class="toggle-track">
          <span class="toggle-thumb"></span>
        </span>
      </label>
    `;

    row.querySelector(".card")?.addEventListener("click", () => {
      selectKey(card.key);
    });

    const toggle = row.querySelector(".key-enabled");
    toggle?.addEventListener("change", () => {
      if (!state.enabled) {
        toggle.checked = false;
        showToast("Turn Armed on before enabling a shortcut", "error");
        return;
      }
      toggleKeyEnabled(card.key, !!toggle.checked);
    });

    els.deck.appendChild(row);

    if (prevFocusKey === card.key) {
      row.querySelector(".card")?.focus({ preventScroll: true });
    }
  }
}

async function toggleKeyEnabled(key, enabled) {
  if (enabled && !state.enabled) {
    showToast("Turn Armed on before enabling a shortcut", "error");
    renderDeck();
    return;
  }
  try {
    const next = await call("set_key_enabled", key, enabled);
    if (next && next.ok === false) {
      showToast(next.message || "Could not update shortcut", "error");
    }
    // Keep current selection/editor; just refresh deck flags
    const prevSelected = state.selected;
    const wasDirty = state.dirty;
    applyState(next);
    state.selected = prevSelected;
    state.dirty = wasDirty;
    renderDeck();
  } catch (err) {
    showToast(String(err.message || err), "error");
    await refreshFull();
  }
}

function escapeHtml(str) {
  return String(str)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
}

let _unsavedResolver = null;

function openUnsavedModal() {
  return new Promise((resolve) => {
    _unsavedResolver = resolve;
    if (!els.unsavedModal) {
      resolve(false);
      return;
    }
    els.unsavedModal.hidden = false;
    document.body.style.overflow = "hidden";
  });
}

function closeUnsavedModal(discard) {
  if (els.unsavedModal) els.unsavedModal.hidden = true;
  if (!els.previewModal || els.previewModal.hidden) {
    document.body.style.overflow = "";
  }
  if (_unsavedResolver) {
    const resolve = _unsavedResolver;
    _unsavedResolver = null;
    resolve(!!discard);
  }
}

async function selectKey(key) {
  if (state.dirty && state.selected && state.selected !== key) {
    const discard = await openUnsavedModal();
    if (!discard) return;
  }

  let card = state.cards.find((c) => c.key === key);
  if (!card) return;

  state.selected = key;
  state.dirty = false;
  hideSaveSuccess();
  renderDeck();

  // Lazy-load list body (keeps boot payload tiny / fast)
  if (card.lines == null) {
    try {
      const detail = await call("get_key", key);
      if (detail?.ok) {
        card = {
          ...card,
          label: detail.label || card.label,
          lines: detail.lines || [],
          count: detail.count ?? (detail.lines || []).length,
          enabled: detail.enabled !== false,
        };
        const idx = state.cards.findIndex((c) => c.key === key);
        if (idx >= 0) state.cards[idx] = card;
      } else {
        card = { ...card, lines: [] };
      }
    } catch (_) {
      card = { ...card, lines: [] };
    }
  }

  // Selection may have changed while loading
  if (state.selected !== key) return;
  fillEditor(card);
  renderDeck();
}

function fillEditor(card) {
  els.editorTitle.textContent = card.label;
  if (els.editorShortcut) {
    els.editorShortcut.dataset.key = card.key;
    els.editorShortcut.setAttribute("aria-label", card.shortcut);
  }
  if (els.editorKeyLetter) {
    els.editorKeyLetter.textContent = card.key.toUpperCase();
  }

  els.labelInput.disabled = false;
  els.linesInput.disabled = false;
  setLinesEditorDisabled(false);
  els.saveBtn.disabled = false;
  els.previewBtn.disabled = false;

  els.labelInput.value = card.label;
  els.linesInput.value = (card.lines || []).join("\n");
  els.lineCount.textContent = String(card.count);
  updateLineGutter();
}

function rawLineCount(text) {
  // Visual rows in the textarea (empty trailing line still counts as a row)
  if (text === "") return 1;
  return text.split(/\r?\n/).length;
}

function updateLineGutter() {
  if (!els.lineGutter || !els.linesInput) return;
  const n = rawLineCount(els.linesInput.value);
  const digits = String(n).length;
  els.lineGutter.style.setProperty("--digits", String(digits));
  let out = "";
  for (let i = 1; i <= n; i += 1) {
    out += (i > 1 ? "\n" : "") + i;
  }
  els.lineGutter.textContent = out;
  els.lineGutter.scrollTop = els.linesInput.scrollTop;
}

function syncGutterScroll() {
  if (!els.lineGutter || !els.linesInput) return;
  els.lineGutter.scrollTop = els.linesInput.scrollTop;
}

function setLinesEditorDisabled(disabled) {
  if (!els.linesEditor) return;
  els.linesEditor.classList.toggle("is-disabled", !!disabled);
}

function markDirty() {
  if (!state.selected) return;
  state.dirty = true;
  els.lineCount.textContent = String(lineCountFromText(els.linesInput.value));
  els.editorTitle.textContent = els.labelInput.value.trim() || "Untitled";
  updateLineGutter();
}

function hideSaveSuccess() {
  clearTimeout(showSaveSuccess._t);
  showSaveSuccess._t = null;
  if (els.saveSuccessGif) els.saveSuccessGif.hidden = true;
}

function syncSuccessGifScrollbarInsets() {
  const ta = els.linesInput;
  const gif = els.saveSuccessGif;
  if (!ta || !gif) return;
  // Detect real overflow scrollbars on the lines field
  const bar = 14; // matches CSS scrollbar width
  const hasV = ta.scrollHeight > ta.clientHeight + 1;
  const hasH = ta.scrollWidth > ta.clientWidth + 1;
  gif.style.setProperty("--sb-right", hasV ? `${bar}px` : "0px");
  gif.style.setProperty("--sb-bottom", hasH ? `${bar}px` : "0px");
}

function showSaveSuccess() {
  const gif = els.saveSuccessGif;
  if (!gif) return;
  syncSuccessGifScrollbarInsets();
  // Restart GIF animation by reloading src
  const src = gif.getAttribute("src") || "success.gif";
  gif.hidden = false;
  gif.src = "";
  gif.src = src + (src.includes("?") ? "&" : "?") + "t=" + Date.now();
  clearTimeout(showSaveSuccess._t);
  showSaveSuccess._t = setTimeout(() => {
    hideSaveSuccess();
  }, 5500);
}

function openErrorModal(title, message) {
  if (!els.errorModal) return;
  if (els.errorModalTitle) els.errorModalTitle.textContent = title || "Error";
  if (els.errorModalLead) els.errorModalLead.textContent = message || "Something went wrong.";
  els.errorModal.hidden = false;
  document.body.style.overflow = "hidden";
  requestAnimationFrame(() => {
    els.errorModalOk?.focus();
  });
}

function closeErrorModal() {
  if (!els.errorModal) return;
  els.errorModal.hidden = true;
  document.body.style.overflow = "";
}

async function saveList() {
  if (!state.selected || state.saving) return;
  const title = (els.labelInput?.value || "").trim();
  if (!title) {
    openErrorModal("Cannot save", "Please enter a list name before saving.");
    // After dismiss, put focus back on the name field
    const focusName = () => {
      els.labelInput?.focus();
      els.errorModalOk?.removeEventListener("click", focusName);
      els.errorModalClose?.removeEventListener("click", focusName);
    };
    els.errorModalOk?.addEventListener("click", focusName, { once: true });
    els.errorModalClose?.addEventListener("click", focusName, { once: true });
    return;
  }
  state.saving = true;
  els.saveBtn?.classList.add("is-saving");
  try {
    const next = await call(
      "save_key",
      state.selected,
      title,
      els.linesInput.value
    );
    if (next && next.ok === false) {
      openErrorModal("Cannot save", next.message || "Could not save this list.");
      return;
    }
    state.dirty = false;
    applyState(next, { forceEditor: true });
    showSaveSuccess();
  } catch (err) {
    openErrorModal("Cannot save", String(err.message || err));
  } finally {
    // Let the 300ms mute-in settle, then animate label back over 300ms
    await new Promise((r) => setTimeout(r, 300));
    els.saveBtn?.classList.remove("is-saving");
    state.saving = false;
  }
}

function openPreviewModal() {
  if (!els.previewModal) return;
  els.previewModal.hidden = false;
  document.body.style.overflow = "hidden";
  requestAnimationFrame(() => {
    const el = els.previewModalText;
    if (el) {
      el.focus();
      const len = el.value.length;
      try {
        el.setSelectionRange(len, len);
      } catch (_) {
        /* ignore */
      }
    }
  });
}

function closePreviewModal() {
  if (!els.previewModal) return;
  els.previewModal.hidden = true;
  document.body.style.overflow = "";
}

async function previewPick() {
  if (!state.selected) return;
  openPreviewModal();
}

async function toggleEnabled() {
  try {
    const prevSelected = state.selected;
    const wasDirty = state.dirty;
    const next = await call("set_enabled", els.enabledToggle.checked);
    applyState(next);
    // Keep editor selection; deck toggles refresh from server state
    if (prevSelected) state.selected = prevSelected;
    state.dirty = wasDirty;
    renderDeck();
  } catch (err) {
    showToast(String(err.message || err), "error");
    els.enabledToggle.checked = !els.enabledToggle.checked;
  }
}

function isTitlebarChrome(target) {
  return !!target?.closest?.(
    ".win-controls, .win-btn, .toggle, button, label, input, a"
  );
}

function wireWindowControls() {
  els.winMin?.addEventListener("click", () => {
    call("window_minimize").catch(() => {});
  });
  els.winClose?.addEventListener("click", () => {
    call("window_close").catch(() => {});
  });

  // Custom drag: whole title bar except controls (reliable on Windows WebView2)
  let dragging = false;
  let originX = 0;
  let originY = 0;
  let startWinX = 0;
  let startWinY = 0;
  let moveQueued = false;
  let pendingX = 0;
  let pendingY = 0;

  async function onTitlebarPointerDown(e) {
    if (e.button !== 0) return;
    if (isTitlebarChrome(e.target)) return;
    try {
      const pos = await call("window_drag_start");
      dragging = true;
      originX = e.screenX;
      originY = e.screenY;
      startWinX = Number(pos?.x) || 0;
      startWinY = Number(pos?.y) || 0;
      els.titlebar?.classList.add("is-dragging");
      try {
        e.currentTarget.setPointerCapture?.(e.pointerId);
      } catch (_) {
        /* ignore */
      }
    } catch (_) {
      dragging = false;
    }
  }

  function flushDragMove() {
    moveQueued = false;
    if (!dragging) return;
    call("window_drag_move", pendingX, pendingY).catch(() => {});
  }

  function onTitlebarPointerMove(e) {
    if (!dragging) return;
    pendingX = startWinX + (e.screenX - originX);
    pendingY = startWinY + (e.screenY - originY);
    if (!moveQueued) {
      moveQueued = true;
      requestAnimationFrame(flushDragMove);
    }
  }

  function onTitlebarPointerUp(e) {
    if (!dragging) return;
    dragging = false;
    els.titlebar?.classList.remove("is-dragging");
    try {
      e.currentTarget.releasePointerCapture?.(e.pointerId);
    } catch (_) {
      /* ignore */
    }
  }

  const bar = els.titlebar;
  if (bar) {
    bar.addEventListener("pointerdown", onTitlebarPointerDown);
    bar.addEventListener("pointermove", onTitlebarPointerMove);
    bar.addEventListener("pointerup", onTitlebarPointerUp);
    bar.addEventListener("pointercancel", onTitlebarPointerUp);
    bar.addEventListener("lostpointercapture", onTitlebarPointerUp);
  }
}

function wire() {
  wireWindowControls();
  els.enabledToggle.addEventListener("change", toggleEnabled);
  els.labelInput.addEventListener("input", markDirty);
  els.linesInput.addEventListener("input", markDirty);
  els.linesInput.addEventListener("scroll", syncGutterScroll);
  els.linesInput.addEventListener("scroll", () => {
    if (els.saveSuccessGif && !els.saveSuccessGif.hidden) {
      syncSuccessGifScrollbarInsets();
    }
  });
  window.addEventListener("resize", () => {
    if (els.saveSuccessGif && !els.saveSuccessGif.hidden) {
      syncSuccessGifScrollbarInsets();
    }
  });
  els.saveBtn.addEventListener("click", saveList);
  els.previewBtn.addEventListener("click", previewPick);

  els.previewModalClose?.addEventListener("click", closePreviewModal);
  els.previewModalDone?.addEventListener("click", closePreviewModal);
  els.previewModal?.addEventListener("click", (e) => {
    if (e.target?.dataset?.closeModal) closePreviewModal();
  });

  els.unsavedKeepBtn?.addEventListener("click", () => closeUnsavedModal(false));
  els.unsavedModalClose?.addEventListener("click", () => closeUnsavedModal(false));
  els.unsavedDiscardBtn?.addEventListener("click", () => closeUnsavedModal(true));
  els.unsavedModal?.addEventListener("click", (e) => {
    if (e.target?.dataset?.closeUnsaved === "cancel") closeUnsavedModal(false);
  });

  els.errorModalOk?.addEventListener("click", closeErrorModal);
  els.errorModalClose?.addEventListener("click", closeErrorModal);
  els.errorModal?.addEventListener("click", (e) => {
    if (e.target?.dataset?.closeError) closeErrorModal();
  });

  document.addEventListener("keydown", (e) => {
    if (e.key !== "Escape") return;
    if (els.errorModal && !els.errorModal.hidden) {
      closeErrorModal();
      return;
    }
    if (els.unsavedModal && !els.unsavedModal.hidden) {
      closeUnsavedModal(false);
      return;
    }
    if (els.previewModal && !els.previewModal.hidden) {
      closePreviewModal();
    }
  });

  const saveOnChord = (e) => {
    if ((e.ctrlKey || e.metaKey) && e.key === "s") {
      e.preventDefault();
      saveList();
    }
  };
  els.linesInput.addEventListener("keydown", saveOnChord);
  els.labelInput.addEventListener("keydown", saveOnChord);
}

async function refreshFull() {
  const s = await call("get_state");
  applyState(s);
  if (!state.selected && s.cards?.length) {
    await selectKey(s.cards[0].key);
  } else if (state.selected) {
    // Refresh active list body if metadata changed
    const card = state.cards.find((c) => c.key === state.selected);
    if (card && card.lines == null && !state.dirty) {
      await selectKey(state.selected);
    }
  }
}

function insertTextAtCaret(text) {
  const el = document.activeElement;
  if (!el) return false;
  const tag = (el.tagName || "").toLowerCase();
  if (tag !== "textarea" && tag !== "input") return false;
  if (el.disabled || el.readOnly) return false;

  const start = el.selectionStart ?? el.value.length;
  const end = el.selectionEnd ?? start;
  const value = el.value ?? "";
  el.value = value.slice(0, start) + text + value.slice(end);
  const pos = start + text.length;
  try {
    el.setSelectionRange(pos, pos);
  } catch (_) {
    /* some inputs don't support selection */
  }
  el.dispatchEvent(new Event("input", { bubbles: true }));
  return true;
}

function isEditableTarget(el) {
  if (!el) return false;
  const tag = (el.tagName || "").toLowerCase();
  if (tag !== "textarea" && tag !== "input") return false;
  if (el.disabled || el.readOnly) return false;
  return true;
}

async function tick() {
  if (!apiReady()) return;
  try {
    if (!state.booted) {
      const s = await call("boot");
      state.booted = true;
      applyState(s);
      if (!state.selected && s.cards?.length) await selectKey(s.cards[0].key);
      return;
    }

    const p = await call("poll");
    if (!p) return;

    if (p.statusTs && p.statusTs !== state.statusTs) {
      state.statusTs = p.statusTs;
    }

    // Single in-app paste path (worker publishes paste only when WildKeys is focused)
    if (p.pasteTs && p.pasteTs > state.pasteTs && p.paste) {
      const prevTs = state.pasteTs;
      state.pasteTs = p.pasteTs;
      // Debounce: ignore a second worker/event within 400ms
      if (p.pasteTs - prevTs < 0.4 && prevTs > 0) {
        /* skip duplicate */
      } else if (isEditableTarget(document.activeElement)) {
        insertTextAtCaret(String(p.paste));
      }
    }

    els.enabledToggle.checked = !!p.enabled;
    els.toggleLabel.textContent = p.enabled ? "Armed" : "Paused";
    state.enabled = !!p.enabled;

    // Only reload cards when the lists file changed
    if (p.revision && p.revision !== state.revision && !state.dirty) {
      await refreshFull();
    }
  } catch (_) {
    /* ignore transient bridge blips */
  }
}

function hideLoadingModal() {
  if (els.loadingModal) {
    els.loadingModal.hidden = true;
  }
  document.body.style.overflow = "";
}

function listsContentReady() {
  // Shortcut rows rendered and at least one list opened in the editor
  const deckReady = !!els.deck && els.deck.children.length > 0 && state.cards.length > 0;
  const editorReady =
    !!state.selected &&
    !!els.labelInput &&
    !els.labelInput.disabled &&
    !!els.linesInput &&
    !els.linesInput.disabled;
  return deckReady && editorReady;
}

async function waitForPaint() {
  await new Promise((r) => requestAnimationFrame(() => requestAnimationFrame(r)));
}

async function loadInitialState() {
  let lastErr = null;
  // Prefer ping then boot — surfaces a clearer failure if API is half-bound
  for (let i = 0; i < 50; i += 1) {
    try {
      if (typeof api()?.ping === "function") {
        await call("ping");
      }
      const s = await call("boot");
      if (s && Array.isArray(s.cards)) return s;
      lastErr = new Error("boot returned no cards");
    } catch (err) {
      lastErr = err;
    }
    await sleep(80);
  }
  throw lastErr || new Error("boot failed");
}

async function bootUi() {
  // Loading modal stays up until lists are loaded and visible
  document.body.style.overflow = "hidden";
  wire();
  updateLineGutter();
  setLinesEditorDisabled(true);

  try {
    await waitForBridge(60000);

    const s = await loadInitialState();
    state.booted = true;
    applyState(s);
    renderDeck();

    if (s.cards?.length) {
      await selectKey(s.cards[0].key);
    }

    let readyTries = 0;
    while (!listsContentReady() && readyTries < 20) {
      if (state.cards.length && els.deck && els.deck.children.length === 0) {
        renderDeck();
      }
      if (!state.cards.length) break;
      await sleep(25);
      readyTries += 1;
    }

    await waitForPaint();
    setInterval(tick, 200);
    hideLoadingModal();
  } catch (err) {
    hideLoadingModal();
    const msg = String(err?.message || err || "");
    if (msg.includes("bridge-timeout") || msg.includes("Bridge not ready")) {
      showToast(
        "Could not connect the app bridge. Quit WildKeys from the tray, then start it with Start WildKeys.bat.",
        "error"
      );
    } else {
      showToast(`Startup error: ${msg}`, "error");
    }
  }
}

document.addEventListener("DOMContentLoaded", bootUi);
// If the bridge becomes ready after a failed boot path, pywebviewready is still handled inside waitForBridge.

/* WildKeys — toned-down neobrutalist, warm & premium */

:root {
  --bg: #e6ded2;
  --bg-deep: #d9d0c2;
  --surface: #f0e9df;
  --surface-2: #f7f1e8;
  --ink: #2f2a26;
  --ink-soft: #5c534c;
  --ink-mute: #8a7f74;
  --line: #3a332e;
  --shadow: rgba(196, 183, 166, 0.5);
  --shadow-deep: rgba(168, 152, 132, 0.5);
  --accent: #c4785a;
  --accent-2: #6f8f7a;
  --accent-3: #b88a4a;
  --danger: #b45a4e;
  --ok: #5d8a6a;
  --radius: 14px;
  --radius-sm: 10px;
  --border: 2.5px solid var(--line);
  --font: "Outfit", "Segoe UI", system-ui, sans-serif;
  --mono: "JetBrains Mono", "Cascadia Mono", Consolas, ui-monospace, monospace;
  --ease: cubic-bezier(0.2, 0.8, 0.2, 1);
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  height: 100%;
  background: var(--bg);
  color: var(--ink);
  font-family: var(--font);
  -webkit-font-smoothing: antialiased;
  overflow: hidden;
}

body {
  background:
    radial-gradient(1200px 600px at 10% -10%, rgba(196, 120, 90, 0.12), transparent 55%),
    radial-gradient(900px 500px at 100% 0%, rgba(111, 143, 122, 0.10), transparent 50%),
    linear-gradient(165deg, #ebe3d7 0%, #e0d6c8 48%, #d9d0c2 100%);
}

button,
input,
textarea {
  font: inherit;
  color: inherit;
}

button {
  cursor: pointer;
  border: none;
  background: none;
}

.app {
  height: 100%;
  display: grid;
  grid-template-rows: auto 1fr;
  gap: 0;
  margin: 0;
  max-width: none;
  overflow: hidden;
  border: 1.5px solid rgba(58, 51, 46, 0.18);
}

.app-body {
  min-height: 0;
  display: flex;
  flex-direction: column;
  padding: 14px 22px 16px;
  overflow: hidden;
}

.app-body .layout {
  flex: 1;
  min-height: 0;
}

/* ── Custom title bar (frameless) ────────────────────── */

.titlebar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  height: 52px;
  min-height: 52px;
  padding: 0 0 0 14px;
  background: rgba(240, 233, 223, 0.72);
  border-bottom: 2px solid rgba(58, 51, 46, 0.12);
  user-select: none;
  flex-shrink: 0;
  cursor: default;
}

.titlebar.is-dragging {
  cursor: grabbing;
}

.titlebar-drag {
  flex: 1;
  min-width: 0;
  height: 100%;
  display: flex;
  align-items: center;
}

.titlebar-right {
  display: flex;
  align-items: center;
  gap: 10px;
  height: 100%;
  flex-shrink: 0;
}

.brand {
  display: flex;
  align-items: center;
  gap: 10px;
}

.mark {
  width: 36px;
  height: 36px;
  display: grid;
  place-items: center;
  flex-shrink: 0;
  background: transparent;
  border: none;
  box-shadow: none;
  padding: 0;
}

.mark-logo {
  width: 36px;
  height: 36px;
  object-fit: contain;
  display: block;
  image-rendering: auto;
  user-select: none;
  pointer-events: none;
}

.brand-text {
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: 2px;
  min-height: 0;
}

.brand-text h1 {
  margin: 0;
  font-size: 1.15rem;
  font-weight: 700;
  letter-spacing: -0.03em;
  line-height: 1;
}

.brand-byline {
  margin: 0;
  font-size: 0.72rem;
  font-weight: 500;
  letter-spacing: 0.01em;
  line-height: 1.1;
  color: rgba(58, 51, 46, 0.55);
}

.win-controls {
  display: flex;
  align-items: center;
  gap: 8px;
  height: 100%;
  padding-right: 10px;
}

/* Same chrome as modal close — shared .modal-close look */
.win-chrome.modal-close {
  width: 28px;
  height: 28px;
  font-size: 0;
  line-height: 0;
}

.win-chrome.win-close:hover {
  background: #c75b4e;
  border-color: #5c2e28;
}

.win-chrome.win-close:hover .chrome-icon {
  filter: brightness(0) invert(1);
}

.win-chrome.win-close:active {
  background: #a84a3f;
}

.win-chrome.win-close:active .chrome-icon {
  filter: brightness(0) invert(1);
}

/* Toggle */

.toggle {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  user-select: none;
  cursor: pointer;
  padding: 6px 10px 6px 8px;
  border-radius: 999px;
  border: var(--border);
  background: var(--surface-2);
  box-shadow: 3px 3px 0 var(--shadow);
}

.toggle input {
  position: absolute;
  opacity: 0;
  pointer-events: none;
}

.toggle-track {
  width: 42px;
  height: 24px;
  border-radius: 999px;
  border: 2px solid var(--line);
  background: var(--bg-deep);
  position: relative;
  transition: background 0.2s var(--ease);
}

.toggle-thumb {
  position: absolute;
  top: 2px;
  left: 2px;
  width: 16px;
  height: 16px;
  border-radius: 50%;
  background: var(--surface-2);
  border: 2px solid var(--line);
  transition: transform 0.2s var(--ease), background 0.2s var(--ease);
}

.toggle input:checked + .toggle-track {
  background: #c9dccf;
}

.toggle input:checked + .toggle-track .toggle-thumb {
  transform: translateX(18px);
  background: var(--ok);
  border-color: #3d5c46;
}

.toggle-label {
  font-size: 0.82rem;
  font-weight: 600;
  min-width: 3.2rem;
}

/* ── Layout ──────────────────────────────────────────── */

.layout {
  display: grid;
  /* Left pane ~200px narrower than a 50/50 split; right takes the rest */
  grid-template-columns: minmax(200px, calc((100% - 16px) / 2 - 100px)) minmax(280px, 1fr);
  gap: 16px;
  min-height: 0;
}

.deck-panel,
.editor-panel {
  min-height: 0;
  border: var(--border);
  border-radius: var(--radius);
  background: var(--surface);
  box-shadow: 5px 5px 0 var(--shadow);
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.panel-head {
  box-sizing: border-box;
  height: 52px;
  min-height: 52px;
  max-height: 52px;
  padding: 0 14px;
  border-bottom: 2px solid rgba(58, 51, 46, 0.12);
  flex-shrink: 0;
  display: flex;
  align-items: center; /* vertical center */
  justify-content: flex-start;
}

.panel-head.deck-head {
  justify-content: space-between;
  gap: 12px;
}

.panel-head.deck-head .toggle {
  flex-shrink: 0;
}

.panel-head h2 {
  margin: 0;
  padding: 0;
  font-size: 1.15rem;
  font-weight: 700;
  letter-spacing: -0.03em;
  line-height: 1;
  display: flex;
  align-items: center;
  min-width: 0;
}

/* ── Deck cards ──────────────────────────────────────── */

.deck {
  flex: 1;
  min-height: 0;
  padding: 8px 10px;
  display: flex;
  flex-direction: column;
  gap: 5px;
  overflow: hidden; /* 10 rows must fit — no scrollbar */
  justify-content: center;
}

.deck-foot {
  flex-shrink: 0;
  margin: 0;
  padding: 10px 14px 12px;
  border-top: 2px solid rgba(58, 51, 46, 0.12);
  font-size: 0.84rem;
  font-weight: 500;
  color: var(--ink-soft);
  line-height: 1.4;
}

.deck-row {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: 8px;
  width: 100%;
  min-width: 0;
  flex: 0 0 auto;
  height: 40px;
}

.deck-row.key-off .card,
.deck-row.key-off .key-combo {
  opacity: 0.62;
}

.card {
  position: relative;
  text-align: left;
  border: var(--border);
  border-radius: 8px;
  background: var(--surface-2);
  box-shadow: 2px 2px 0 var(--shadow);
  padding: 0 10px;
  height: 100%;
  transition: background 0.15s var(--ease), outline-color 0.15s var(--ease), opacity 0.15s var(--ease);
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: flex-start;
  gap: 10px;
  flex: 1;
  min-width: 0;
  min-height: 0;
  cursor: pointer;
  font: inherit;
  color: inherit;
  outline: 2px solid transparent;
  outline-offset: 0;
}

.card:hover {
  background: #ebe3d6;
}

.card:active {
  background: #e3d9c9;
}

.card.active {
  background: #faf6ef;
  outline-color: rgba(196, 120, 90, 0.4);
}

.card.active:hover {
  background: #f3ebe0;
}

.key-combo {
  display: flex;
  align-items: center;
  flex-wrap: nowrap;
  gap: 5px;
  flex-shrink: 0;
  height: 100%;
}

.row-toggle {
  flex-shrink: 0;
  padding: 3px 5px;
  box-shadow: 2px 2px 0 var(--shadow);
}

.row-toggle.is-locked {
  opacity: 0.45;
  cursor: default;
  box-shadow: 1px 1px 0 var(--shadow);
}

.row-toggle.is-locked input:disabled {
  cursor: default;
}

.toggle-sm .toggle-track {
  width: 32px;
  height: 18px;
}

.toggle-sm .toggle-thumb {
  width: 10px;
  height: 10px;
  top: 2px;
  left: 2px;
}

.toggle-sm input:checked + .toggle-track .toggle-thumb {
  transform: translateX(14px);
}

.key-badge {
  height: 22px;
  min-width: 22px;
  padding: 0 7px;
  border-radius: 7px;
  border: 2px solid var(--line);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font);
  font-weight: 600;
  font-size: 0.62rem;
  letter-spacing: 0.02em;
  text-transform: uppercase;
  text-align: center;
  background: var(--bg);
  line-height: 1;
  box-shadow: 1px 1px 0 var(--shadow);
}

.key-badge.mod {
  color: var(--ink);
}

.key-badge.letter {
  width: 26px;
  min-width: 26px;
  max-width: 26px;
  padding: 0;
  box-sizing: border-box;
  color: var(--ink);
}

/*
 * Per-shortcut badge tint — same for Ctrl/Alt/letter on a row.
 * Hues follow list meaning (soft pastels that fit the sand UI):
 *   Q shot      warm clay (framing / camera body)
 *   W angle     cool steel (lens / geometry)
 *   R lighting  golden amber (light)
 *   T pose      blush rose (body / gesture)
 *   Y backdrop  sage green (environment)
 *   U art style soft violet (creative)
 *   I hair      warm cocoa (hair)
 *   D face      coral peach (expression)
 *   G wardrobe  denim mist (cloth)
 *   K details   champagne (jewelry / polish)
 */
.deck-row[data-key="q"] .key-badge,
.editor-keys[data-key="q"] .key-badge { background: #e8cfc3; } /* Shot type */
.deck-row[data-key="w"] .key-badge,
.editor-keys[data-key="w"] .key-badge { background: #cfdce8; } /* Camera angle */
.deck-row[data-key="r"] .key-badge,
.editor-keys[data-key="r"] .key-badge { background: #efdfb6; } /* Lighting */
.deck-row[data-key="t"] .key-badge,
.editor-keys[data-key="t"] .key-badge { background: #ebcfd6; } /* Pose */
.deck-row[data-key="y"] .key-badge,
.editor-keys[data-key="y"] .key-badge { background: #d2e3d4; } /* Background */
.deck-row[data-key="u"] .key-badge,
.editor-keys[data-key="u"] .key-badge { background: #dcd3eb; } /* Art style */
.deck-row[data-key="i"] .key-badge,
.editor-keys[data-key="i"] .key-badge { background: #e3d2c0; } /* Hair */
.deck-row[data-key="d"] .key-badge,
.editor-keys[data-key="d"] .key-badge { background: #f0d0c8; } /* Expression */
.deck-row[data-key="g"] .key-badge,
.editor-keys[data-key="g"] .key-badge { background: #d0dbe6; } /* Wardrobe */
.deck-row[data-key="k"] .key-badge,
.editor-keys[data-key="k"] .key-badge { background: #e8dfc0; } /* Details */

.card-label {
  font-weight: 650;
  font-size: 0.86rem;
  letter-spacing: -0.02em;
  line-height: 1.1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  text-align: left;
  min-width: 0;
  flex: 1;
}

/* ── Editor ──────────────────────────────────────────── */

.editor-panel {
  padding: 0 0 14px;
}

.editor-head {
  width: 100%;
  display: flex;
  justify-content: space-between;
  align-items: center; /* vertical center title + shortcut */
  gap: 12px;
}

.editor-head > div {
  min-width: 0;
  height: 100%;
  display: flex;
  align-items: center;
}

.editor-head h2 {
  margin: 0;
  padding: 0;
  font-size: 1.15rem;
  font-weight: 700;
  letter-spacing: -0.03em;
  line-height: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  display: flex;
  align-items: center;
}

.editor-keys {
  flex-shrink: 0;
  height: auto;
  align-self: center;
}

.field {
  display: flex;
  flex-direction: column;
  gap: 6px;
  padding: 12px 18px 0;
  font-size: 0.78rem;
  font-weight: 600;
  color: var(--ink-soft);
}

.field.grow {
  flex: 1;
  min-height: 0;
}

.field-label {
  font-size: 0.95rem;
  font-weight: 700;
  letter-spacing: -0.02em;
  color: var(--ink);
  padding-left: 12px;
}

.field-row {
  display: flex;
  justify-content: space-between;
  align-items: baseline;
}

.count {
  font-family: var(--mono);
  font-size: 0.72rem;
  font-weight: 600;
  color: var(--ink-mute);
}

.field input {
  width: 100%;
  border: var(--border);
  border-radius: var(--radius-sm);
  background: var(--surface-2);
  padding: 11px 12px;
  outline: none;
  box-shadow: inset 0 0 0 0 transparent;
  transition: box-shadow 0.15s var(--ease), border-color 0.15s var(--ease);
  font-size: 1rem;
  font-weight: 500;
}

.field input:focus {
  box-shadow: 0 0 0 3px rgba(196, 120, 90, 0.22);
}

.field input:disabled {
  opacity: 0.55;
  cursor: not-allowed;
}

.lines-editor {
  position: relative;
  flex: 1;
  min-height: 180px;
  display: flex;
  border: var(--border);
  border-radius: var(--radius-sm);
  background: var(--surface-2);
  overflow: hidden;
  transition: box-shadow 0.15s var(--ease);
}

.lines-main {
  position: relative;
  flex: 1;
  min-width: 0;
  min-height: 0;
  display: flex;
  overflow: hidden;
}

.save-success-gif {
  --sb-right: 0px;
  --sb-bottom: 0px;
  position: absolute;
  /*
    Layer: text (textarea) < GIF < scrollbars.
    Insets are set in JS only when a scrollbar is actually present;
    otherwise the GIF sits flush on the bottom-right borders.
  */
  right: var(--sb-right);
  bottom: var(--sb-bottom);
  top: auto;
  transform: none;
  width: auto;
  height: 300px;
  max-height: calc(100% - var(--sb-bottom));
  object-fit: contain;
  object-position: bottom right;
  pointer-events: none;
  z-index: 2;
}

.save-success-gif[hidden] {
  display: none !important;
}

.lines-editor:focus-within {
  box-shadow: 0 0 0 3px rgba(196, 120, 90, 0.22);
}

.lines-editor.is-disabled {
  opacity: 0.55;
}

.line-gutter {
  --gutter-pad-x: 8px;
  --digits: 1;
  position: relative;
  z-index: 3;
  flex: 0 0 auto;
  /* Digit block width + equal padding on both sides */
  width: calc(var(--digits) * 1ch + (2 * var(--gutter-pad-x)));
  box-sizing: border-box;
  padding: 11px var(--gutter-pad-x);
  margin: 0;
  border: none;
  border-right: 2px solid rgba(58, 51, 46, 0.12);
  background: var(--bg-deep);
  color: var(--ink-mute);
  font-family: var(--mono);
  font-size: 0.72rem;
  font-weight: 600;
  font-variant-numeric: tabular-nums;
  /* Match textarea row height: 0.9rem * 1.5 */
  line-height: 1.35rem;
  text-align: right;
  white-space: pre;
  overflow: hidden;
  user-select: none;
  tab-size: 2;
}

.lines-editor textarea {
  position: relative;
  z-index: 1;
  flex: 1;
  min-width: 0;
  min-height: 0;
  width: 100%;
  height: 100%;
  border: none;
  border-radius: 0;
  background: transparent;
  padding: 11px 12px;
  outline: none;
  resize: none;
  line-height: 1.35rem;
  font-family: var(--font);
  font-size: 0.9rem;
  font-weight: 450;
  color: var(--ink);
  white-space: pre;
  overflow: auto;
  tab-size: 2;
}

.lines-editor textarea:disabled {
  cursor: not-allowed;
}

.editor-actions {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  padding: 14px 18px 0;
}

.btn {
  border: var(--border);
  border-radius: 10px;
  padding: 10px 16px;
  font-weight: 650;
  font-size: 0.84rem;
  letter-spacing: -0.01em;
  box-shadow: 3px 3px 0 var(--shadow);
  transition: background 0.15s var(--ease), filter 0.15s var(--ease);
}

.btn:hover:not(:disabled):not(.is-saving) {
  filter: brightness(0.97);
}

.btn:active:not(:disabled):not(.is-saving) {
  filter: brightness(0.93);
}

.btn:disabled {
  opacity: 0.45;
  cursor: not-allowed;
  box-shadow: 2px 2px 0 var(--shadow);
}

.btn.primary {
  background: #d4a08c;
  color: var(--ink);
  transition:
    background 0.15s var(--ease),
    filter 0.15s var(--ease),
    color 300ms ease;
}

.btn.primary:hover:not(:disabled):not(.is-saving) {
  background: #c9917a;
}

/* Save in progress: only the label color mutes (not the full button) */
.btn.primary.is-saving {
  color: rgba(47, 42, 38, 0.38);
  cursor: default;
}

.btn.ghost {
  background: var(--surface-2);
}

.toast {
  margin: 12px 18px 0;
  padding: 10px 12px;
  border-radius: 10px;
  border: 2px solid var(--line);
  background: #e5efe6;
  font-size: 0.78rem;
  font-weight: 500;
  color: var(--ink-soft);
